Use ASP.NET Core's **`WebApplicationFactory<T>`** — it hosts your app in-memory and gives you an `HttpClient` that hits it directly (no ports, no real server).

### Setup

```bash
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```

### Example test

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using System.Net.Http.Json;
using System.Text.Json;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsCall_ExecutesTool()
    {
        // Initialize first (MCP requires it)
        await InitializeSession();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var content = body.GetProperty("result")
                         .GetProperty("content")[0];
        Assert.Equal("text", content.GetProperty("type").GetString());
    }

    private async Task InitializeSession() { /* send initialize as above */ }
}
```

### Key points

| Concern | Approach |
|---|---|
| **No real server** | `WebApplicationFactory` hosts in-process |
| **Swap dependencies** | Override `ConfigureWebHost` to replace DB/services with fakes |
| **Session/state** | Reuse the same `HttpClient` instance per session |
| **SSE streaming** | Read `response.Content.ReadAsStreamAsync()` and parse `data:` lines |
| **Notifications** | Send JSON-RPC messages with no `id` field, assert 202/204 |

### Overriding services (e.g., fake a DB)

```csharp
public class CustomFactory : WebApplicationFactory<Program>
{
    protected override void ConfigureWebHost(IWebHostBuilder builder)
    {
        builder.ConfigureServices(services =>
        {
            // Replace a real service with a fake
            services.RemoveAll<IMyDatabase>();
            services.AddSingleton<IMyDatabase, FakeDatabase>();
        });
    }
}
```

Then use `IClassFixture<CustomFactory>` instead.

This gives you full MCP protocol coverage (initialize → list tools → call tools → notifications) entirely in-process with no network overhead.
